- Valores de `settings` (title, description, text, url) — são texto traduzido
- IDs dos elementos Elementor — são regenerados a cada save sem mudança estrutural (causa raiz de falsos positivos se usados no hash)
- `_icl_translation_*` metas

### Lógica de severidade (corrigida)

| Condição | Severidade |
|----------|-----------|
| `struct_hash` igual | **nenhuma** — pular |
| `_elementor_data` vazio/inválido na **tradução** | **grave** — tradução sem dados Elementor |
| `struct_hash` diferente + contagens iguais + `page_settings_hash` diferente | **leve** — só settings visuais |
| `struct_hash` diferente + contagens iguais + `page_settings_hash` igual | **moderada** — sequência de widgets reordenada |
| `struct_hash` diferente + diferença de 1-4 widgets/seções | **moderada** — elementos adicionados/removidos |
| `struct_hash` diferente + diferença ≥ 5 elementos ou seção removida | **grave** — estrutura significativamente reescrita |

> **Falso positivo a evitar:** Elementor regenera IDs ao salvar sem mudança estrutural. Por isso o
> fingerprint usa `struct_hash` baseado em `types_sequence` (não IDs) como critério primário.
>
> **Nota sobre profundidade:** A sequência inclui marcadores `[` e `]` para abrir/fechar níveis —
> assim `section > column > widget A` ≠ `section > widget A` (mesmo que ambos tenham mesmos elTypes).

---

## Aviso Crítico: Risco de Data Loss em Traduções Manuais

**Este aviso deve constar no corpo da operação na skill:**

Quando o tradutor editou a tradução **diretamente no Elementor** (em vez do WPML Translation
Editor), o texto traduzido fica dentro de `_elementor_data` do post traduzido — NÃO em
`_icl_translation_*` metas. Nesse caso, a re-sincronização **sobrescreve o texto traduzido**.

O script de re-renderização em lote deve detectar esse cenário antes de sobrescrever:
- Comparar se algum texto de widget entre o original e a tradução é diferente
- Se sim: marcar o par com flag `has_manual_translation: true` e avisar explicitamente
- Não executar sem confirmação adicional para esses pares

---

## Script PHP de Auditoria (`elementor-struct-diff.php`)

Arquivo gerado como `/tmp/elementor-struct-diff.php` e executado via `wp eval-file`.

### Parâmetros configuráveis (substituídos pelo Poliglota antes de copiar)

```php
$source_lang = 'pt-br';       // idioma original
$target_lang = 'en';          // idioma da tradução
$post_types  = ['page'];      // ou ['page','post','elementor_library', ...]
$post_status = ['publish'];   // configurável: ['publish','draft','future']
```

### Script completo

```php
<?php
// NOTA: $wpdb->prefix e $wpdb->posts mudam conforme o --url= passado ao WP-CLI
// Blog 1 (raiz): wp_posts / wp_ | Blog 2 (/cultura/): wp_2_posts / wp_2_
// wp_icl_translations é GLOBAL (não tem prefixo por blog — compartilhado por todo o multisite)

$source_lang = 'pt-br';
$target_lang = 'en';
$post_types  = ['page'];
$post_status = ['publish'];

global $wpdb;

// --- Função de fingerprint estrutural com profundidade ---
function elementor_structural_fingerprint($raw_json) {
    if (empty($raw_json)) {
        return ['struct_hash' => '', 'types_sequence' => [], 'counts' => [],
                'empty' => true, 'ps_hash' => ''];
    }
    $elements = json_decode($raw_json, true);
    if (!is_array($elements)) {
        return ['struct_hash' => '', 'types_sequence' => [], 'counts' => [],
                'invalid_json' => true, 'ps_hash' => ''];
    }

    $seq    = [];
    $counts = ['section' => 0, 'container' => 0, 'column' => 0, 'widget' => 0];

    // Travessia DFS com marcadores de abertura/fechamento de nível
    $walk = function($items) use (&$walk, &$seq, &$counts) {
        foreach ($items as $el) {
            $type = $el['elType'] ?? '';
            if ($type === 'widget') {
                $wt = $el['widgetType'] ?? 'unknown';
                $seq[] = "w:$wt";
                $counts['widget']++;
            } else {
                $seq[] = $type . '[';          // abre nível
                if (isset($counts[$type])) $counts[$type]++;
                if (!empty($el['elements'])) {
                    $walk($el['elements']);
                }
                $seq[] = ']';                  // fecha nível
            }
        }
    };
    $walk($elements);

    return [
        'struct_hash'    => md5(implode(',', $seq)),
        'types_sequence' => $seq,
        'counts'         => $counts,
    ];
}

// --- Extrator de texto para detecção de tradução manual ---
function elementor_extract_texts($raw_json) {
    if (empty($raw_json)) return [];
    $elements = json_decode($raw_json, true);
    if (!is_array($elements)) return [];

    $texts = [];
    $walk = function($items) use (&$walk, &$texts) {
        foreach ($items as $el) {
            $settings = $el['settings'] ?? [];
            foreach (['title','text','editor','description','caption','html'] as $key) {
                if (!empty($settings[$key])) {
                    // Normalizar: remover tags HTML e whitespace extra
                    $clean = trim(wp_strip_all_tags($settings[$key]));
                    if ($clean !== '') $texts[] = $clean;
                }
            }
            if (!empty($el['elements'])) $walk($el['elements']);
        }
    };
    $walk($elements);
    return $texts;
}

// --- Carregar todos os post_ids dos pares primeiro ---
$all_pairs = [];
foreach ($post_types as $post_type) {
    $is_translatable = apply_filters('wpml_is_translated_post_type', null, $post_type);
    if (!$is_translatable) continue;

    $element_type = apply_filters('wpml_element_type', $post_type);
    $status_ph    = implode(',', array_fill(0, count($post_status), '%s'));

    $rows = $wpdb->get_results(
        $wpdb->prepare(
            "SELECT
               p.ID           AS source_id,
               p.post_title,
               ts.element_id  AS translated_id,
               t.trid
             FROM {$wpdb->posts} p
             INNER JOIN {$wpdb->prefix}icl_translations t
               ON t.element_id = p.ID
               AND t.element_type = %s
               AND t.language_code = %s
             INNER JOIN {$wpdb->prefix}icl_translations ts
               ON ts.trid = t.trid
               AND ts.element_type = %s
               AND ts.language_code = %s
             WHERE p.post_type = %s
               AND p.post_status IN ($status_ph)
             ORDER BY p.ID",
            $element_type, $source_lang,
            $element_type, $target_lang,
            $post_type,
            ...$post_status
        ),
        ARRAY_A
    );

    foreach ($rows as $row) {
        $row['post_type'] = $post_type;
        $all_pairs[] = $row;
    }
}

// --- Carregar metadados em lote (1 query, não N×2) ---
$all_ids = [];
foreach ($all_pairs as $pair) {
    $all_ids[] = (int)$pair['source_id'];
    $all_ids[] = (int)$pair['translated_id'];
}
$all_ids = array_unique($all_ids);

$meta_keys = ['_elementor_data', '_elementor_page_settings'];
$id_ph     = implode(',', array_fill(0, count($all_ids), '%d'));
$key_ph    = implode(',', array_fill(0, count($meta_keys), '%s'));

$meta_rows = $wpdb->get_results(
    $wpdb->prepare(
        "SELECT post_id, meta_key, meta_value
         FROM {$wpdb->postmeta}
         WHERE post_id IN ($id_ph)
           AND meta_key IN ($key_ph)",
        ...$all_ids,
        ...$meta_keys
    ),
    ARRAY_A
);

$meta = [];
foreach ($meta_rows as $row) {
    $meta[$row['post_id']][$row['meta_key']] = $row['meta_value'];
}

// --- Comparar fingerprints par-a-par ---
$divergent = [];

foreach ($all_pairs as $pair) {
    $src_id = (int)$pair['source_id'];
    $trs_id = (int)$pair['translated_id'];

    $src_raw = $meta[$src_id]['_elementor_data']        ?? '';
    $trs_raw = $meta[$trs_id]['_elementor_data']        ?? '';
    $src_ps  = $meta[$src_id]['_elementor_page_settings']  ?? '';
    $trs_ps  = $meta[$trs_id]['_elementor_page_settings']  ?? '';

    $fp_src = elementor_structural_fingerprint($src_raw);
    $fp_trs = elementor_structural_fingerprint($trs_raw);

    // Hashes de page_settings com JSON_SORT_KEYS para evitar falsos positivos por ordem de chaves
    $src_ps_arr = $src_ps ? (json_decode($src_ps, true) ?? []) : [];
    $trs_ps_arr = $trs_ps ? (json_decode($trs_ps, true) ?? []) : [];
    ksort($src_ps_arr); ksort($trs_ps_arr);
    $ps_match = (json_encode($src_ps_arr) === json_encode($trs_ps_arr));

    // Determinar severidade
    if (!empty($fp_trs['empty']) || !empty($fp_trs['invalid_json'])) {
        $severity = 'grave';
        $reason   = 'translated_elementor_data_missing_or_invalid';
    } elseif ($fp_src['struct_hash'] === $fp_trs['struct_hash'] && $ps_match) {
        continue; // idêntico — pular
    } elseif ($fp_src['struct_hash'] === $fp_trs['struct_hash'] && !$ps_match) {
        $severity = 'leve';
        $reason   = 'page_settings_diverge';
    } else {
        // Struct hash diferente — calcular magnitude
        $cnt_src    = $fp_src['counts'];
        $cnt_trs    = $fp_trs['counts'];
        $total_diff = array_sum(array_map(
            fn($k) => abs(($cnt_src[$k] ?? 0) - ($cnt_trs[$k] ?? 0)),
            array_keys($cnt_src)
        ));

        if ($total_diff === 0 && $ps_match) {
            // Sequência diferente mas contagens iguais — reordenação
            $severity = 'moderada';
            $reason   = 'widget_sequence_reordered';
        } elseif ($total_diff >= 5 || (($cnt_src['section'] ?? 0) !== ($cnt_trs['section'] ?? 0))) {
            $severity = 'grave';
            $reason   = 'major_structural_change';
        } else {
            $severity = 'moderada';
            $reason   = 'elements_added_or_removed';
        }
    }

    // Detectar tradução manual (texto diferente em _elementor_data)
    $src_texts     = elementor_extract_texts($src_raw);
    $trs_texts     = elementor_extract_texts($trs_raw);
    $has_manual_tr = !empty($trs_texts) && ($src_texts !== $trs_texts);

    // Widgets presentes apenas em cada lado
    $src_widgets = array_count_values(array_filter($fp_src['types_sequence'], fn($t) => strpos($t, 'w:') === 0));
    $trs_widgets = array_count_values(array_filter($fp_trs['types_sequence'], fn($t) => strpos($t, 'w:') === 0));

    $divergent[] = [
        'source_id'         => $src_id,
        'translated_id'     => $trs_id,
        'post_type'         => $pair['post_type'],
        'post_title'        => $pair['post_title'],
        'trid'              => (int)$pair['trid'],
        'severity'          => $severity,
        'reason'            => $reason,
        'has_manual_tr'     => $has_manual_tr,   // AVISO: tradução pode estar em _elementor_data
        'diff' => [
            'struct_hash_match'   => ($fp_src['struct_hash'] === $fp_trs['struct_hash']),
            'page_settings_match' => $ps_match,
            'counts_source'       => $fp_src['counts'],
            'counts_trans'        => $fp_trs['counts'],
            'widgets_src_only'    => array_keys(array_diff_key($src_widgets, $trs_widgets)),
            'widgets_trs_only'    => array_keys(array_diff_key($trs_widgets, $src_widgets)),
        ],
    ];
}

// Agrupar por post_type
$by_type = [];
foreach ($divergent as $item) {
    $by_type[$item['post_type']][] = $item;
}

$result = [
    'source_lang'     => $source_lang,
    'target_lang'     => $target_lang,
    'total_scanned'   => count($all_pairs),
    'total_divergent' => count($divergent),
    'has_manual_tr_count' => count(array_filter($divergent, fn($d) => $d['has_manual_tr'])),
    'by_severity' => [
        'grave'    => count(array_filter($divergent, fn($d) => $d['severity'] === 'grave')),
        'moderada' => count(array_filter($divergent, fn($d) => $d['severity'] === 'moderada')),
        'leve'     => count(array_filter($divergent, fn($d) => $d['severity'] === 'leve')),
    ],
    'by_type'    => $by_type,
    'divergent'  => $divergent,
];

echo json_encode($result, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
```

